proof fn phi_1_execution_equality_forces_fn_equality(f: spec_fn(nat) -> int, g: spec_fn(nat) -> int)
    requires
        forall |i: nat| #[trigger] f(i) == g(i),
    ensures
        f == g,
{
    let ex1 = Execution { nat_to_state: f };
    let ex2 = Execution { nat_to_state: g };
    execution_equality::<int>(ex1, ex2);
}

proof fn phi_2_always_unfold_intensional_bridge(ex: Execution<int>, p: TempPred<int>, i: nat)
    requires
        always(p).satisfied_by(ex),
    ensures
        p.satisfied_by(ex.suffix(i)),
{
    always_unfold::<int>(ex, p);
}

proof fn phi_3_always_propagate_chains_arbitrarily(ex: Execution<int>, p: TempPred<int>, i: nat, j: nat)
    requires
        always(p).satisfied_by(ex),
    ensures
        always(p).satisfied_by(ex.suffix(i).suffix(j)),
{
    always_propagate_forwards::<int>(ex, p, i);
    always_propagate_forwards::<int>(ex.suffix(i), p, j);
}

proof fn phi_4_suffix_composition_equals_addition(ex: Execution<int>, i: nat, j: nat)
    ensures
        ex.suffix(i).suffix(j) == ex.suffix(i + j),
{
    execution_equality::<int>(ex.suffix(i).suffix(j), ex.suffix(i + j));
}

proof fn phi_5_always_double_nesting(ex: Execution<int>, p: TempPred<int>)
    requires
        always(p).satisfied_by(ex),
    ensures
        always(always(p)).satisfied_by(ex),
{
    assert forall |i: nat| always(p).satisfied_by(#[trigger] ex.suffix(i)) by {
        always_propagate_forwards::<int>(ex, p, i);
    };
}
